import{_ as o,o as t,c as a,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"123. Ados","description":"","frontmatter":{"title":"123. Ados","eba":"Mental Health Services 2024-2028","topics":["hours","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/123-ados.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/123-ados.md"}'),r={name:"ebas/mental-health/health-professionals/hours-of-work/123-ados.md"};function n(l,e,i,h,p,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="_123-ados" tabindex="-1">123. Ados <a class="header-anchor" href="#_123-ados" aria-label="Permalink to &quot;123. Ados&quot;">​</a></h1><p><strong>123.1</strong> All full-time Employees covered by this Section 3 are entitled to an ADO.</p><p><strong>123.2</strong> An Employee who receives an ADO and who is transferred to a new position within the Employer’s business will continue to receive an ADO unless otherwise agreed.</p><p><strong>123.3</strong> New Employees will be appraised of the relevant department’s work arrangements and provisions regarding hours of work and entitlements to an ADO.</p><p><strong>123.4</strong> The Employer will not refuse new Employees the option of an ADO.</p><p><strong>123.5</strong> Taking of ADOs Wherever practicable, an ADO will be on the date requested by the Employee.</p><p><strong>123.6</strong> Public Holiday and ADO Where an Employee&#39;s ADO falls on a public holiday, another day shall be determined by the Employer to be Taken in lieu thereof, within the same 4-week cycle (where practicable).</p>',7)])])}const f=o(r,[["render",n]]);export{m as __pageData,f as default};
